// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');
const { sendError } = require('../../lib/errors');

let commentsStore = [];

async function addComment(projectId, taskId, content) {
  const task = await tasksService.getTasksByStatus(projectId).find(t => t.id === taskId);
  if (!task) {
    return null;
  }

  const comment = { id: randomUUID(), projectId, taskId, content };
  commentsStore.push(comment);
  return comment;
}

module.exports = {
  addComment,
};

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

let membersStore = [];

async function addMember(projectId, userId, role) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }

  const existingMember = membersStore.find(m => m.projectId === projectId && m.userId === userId);
  if (existingMember) {
    return null;
  }

  const member = { id: randomUUID(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

module.exports = {
  addMember,
};

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let projectsStore = [];

async function createProject(name) {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    return null;
  }

  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

async function getAllProjects() {
  return projectsStore;
}

module.exports = {
  createProject,
  getAllProjects,
};

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

let tasksStore = [];

async function createTask(projectId, title) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }

  const task = { id: randomUUID(), projectId, title, status: 'todo' };
  tasksStore.push(task);
  return task;
}

async function getTasksByStatus(projectId, status) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }

  return tasksStore.filter(task => task.projectId === projectId && (status ? task.status === status : true));
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = await projectsService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return null;
  }

  const taskIndex = tasksStore.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  createTask,
  getTasksByStatus,
  updateTaskStatus,
};
